/**
 * 提供从Web上获取页面内容的服务。
 * 增强：增加严格的URL校验、DNS解析与IP段过滤、禁用自动重定向并对每次重定向目标再次校验，以防止SSRF。
 */
@Service
public class WebPageFetcherService {

    private static final int CONNECT_TIMEOUT_MS = 5000;
    private static final int READ_TIMEOUT_MS = 7000;
    private static final int CONNECTION_REQUEST_TIMEOUT_MS = 5000;
    private static final int MAX_REDIRECTS = 5;

    // 仅允许 http/https
    private static final Set<String> ALLOWED_SCHEMES = new HashSet<>(Arrays.asList("http", "https"));
    // 仅允许 80/443 端口（或未指定，即 -1）
    private static final Set<Integer> ALLOWED_PORTS = new HashSet<>(Arrays.asList(-1, 80, 443));
    // 禁止的伪域名/后缀
    private static final Set<String> BLOCKED_HOST_SUFFIX = new HashSet<>(Arrays.asList(
            ".onion", ".local", ".localhost", ".localdomain"
    ));
    private static final Set<String> BLOCKED_EXACT_HOSTS = new HashSet<>(Arrays.asList(
            "localhost", "local", "localhost.localdomain"
    ));

    private final RestTemplate safeRestTemplate;

    public WebPageFetcherService(RestTemplate ignored) {
        // 使用带有安全DNS解析器并禁用自动重定向的 HttpClient
        RequestConfig requestConfig = RequestConfig.custom()
                .setConnectTimeout(CONNECT_TIMEOUT_MS)
                .setSocketTimeout(READ_TIMEOUT_MS)
                .setConnectionRequestTimeout(CONNECTION_REQUEST_TIMEOUT_MS)
                .setRedirectsEnabled(false)
                .build();

        CloseableHttpClient httpClient = HttpClients.custom()
                .setDefaultRequestConfig(requestConfig)
                .setDnsResolver(new SafeDnsResolver())
                .disableRedirectHandling() // 确保不自动跟随重定向，手工验证每次跳转
                .build();

        HttpComponentsClientHttpRequestFactory requestFactory = new HttpComponentsClientHttpRequestFactory(httpClient);
        RestTemplate rt = new RestTemplate(requestFactory);
        this.safeRestTemplate = rt;
    }

    /**
     * 根据提供的URL获取其HTML页面内容。
     * 仅允许访问公共互联网的 http/https 站点，禁止访问内网/本地/保留地址，并对重定向进行逐跳校验。
     *
     * @param url 目标网页的完整URL，例如 "https://www.example.com"
     * @return 返回网页的HTML内容字符串。如果无法访问或发生错误，则返回null。
     */
    public String getPageContent(String url) {
        try {
            URI uri = validateAndNormalize(url);
            return fetchFollowingRedirects(uri, MAX_REDIRECTS);
        } catch (IllegalArgumentException e) {
            System.err.println("Rejected URL (security validation failed): " + url + " - " + e.getMessage());
            return null;
        } catch (RestClientException e) {
            System.err.println("Error fetching content from URL: " + url + " - " + e.getMessage());
            return null;
        }
    }

    private String fetchFollowingRedirects(URI startUri, int maxRedirects) {
        URI current = startUri;
        for (int i = 0; i <= maxRedirects; i++) {
            HttpHeaders headers = new HttpHeaders();
            headers.set("User-Agent", "SafeFetcher/1.0");
            headers.set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8");
            HttpEntity<Void> entity = new HttpEntity<>(headers);

            ResponseEntity<String> response = safeRestTemplate.exchange(current, HttpMethod.GET, entity, String.class);
            int status = response.getStatusCodeValue();

            if (status >= 200 && status < 300) {
                return response.getBody();
            }
            if (status >= 300 && status < 400) {
                String location = response.getHeaders().getFirst("Location");
                if (location == null || location.isEmpty()) {
                    System.err.println("Redirect without Location header from: " + current);
                    return null;
                }
                URI next = resolveRedirect(current, location);
                // 对重定向目标进行同样的严格校验
                current = validateAndNormalize(next.toString());
                continue;
            }
            // 对于其他状态码，视为失败
            System.err.println("Non-success HTTP status " + status + " from: " + current);
            return null;
        }
        System.err.println("Too many redirects for: " + startUri);
        return null;
    }

    private URI resolveRedirect(URI base, String location) {
        URI loc = URI.create(location);
        if (loc.isAbsolute()) {
            return loc;
        }
        return base.resolve(loc);
    }

    private URI validateAndNormalize(String inputUrl) {
        URI uri;
        try {
            uri = new URI(inputUrl.trim());
        } catch (URISyntaxException e) {
            throw new IllegalArgumentException("Invalid URL syntax");
        }

        String scheme = uri.getScheme();
        if (scheme == null || !ALLOWED_SCHEMES.contains(scheme.toLowerCase())) {
            throw new IllegalArgumentException("Only http/https are allowed");
        }

        if (uri.getRawUserInfo() != null) {
            throw new IllegalArgumentException("User info in URL is not allowed");
        }

        String host = uri.getHost();
        if (host == null || host.isEmpty()) {
            throw new IllegalArgumentException("Host is required");
        }
        String asciiHost = IDN.toASCII(host);

        // 阻止明显的危险后缀和本地域名
        String lowerAsciiHost = asciiHost.toLowerCase();
        if (BLOCKED_EXACT_HOSTS.contains(lowerAsciiHost)) {
            throw new IllegalArgumentException("Blocked host");
        }
        for (String suffix : BLOCKED_HOST_SUFFIX) {
            if (lowerAsciiHost.endsWith(suffix)) {
                throw new IllegalArgumentException("Blocked host suffix: " + suffix);
            }
        }

        int port = uri.getPort();
        if (!ALLOWED_PORTS.contains(port)) {
            throw new IllegalArgumentException("Port not allowed");
        }

        // 预解析并校验所有解析到的IP地址均为公共地址
        try {
            InetAddress[] resolved = InetAddress.getAllByName(asciiHost);
            for (InetAddress addr : resolved) {
                if (!isPublicAddress(addr)) {
                    throw new IllegalArgumentException("Host resolves to a non-public address");
                }
            }
        } catch (UnknownHostException e) {
            throw new IllegalArgumentException("Host cannot be resolved");
        }

        // 规范化URI（移除片段，使用ASCII主机名）
        try {
            String path = uri.getRawPath();
            String query = uri.getRawQuery();
            return new URI(
                    scheme.toLowerCase(),
                    null, // no userinfo
                    asciiHost,
                    port,
                    path == null || path.isEmpty() ? "/" : path,
                    query,
                    null // drop fragment
            );
        } catch (URISyntaxException e) {
            throw new IllegalArgumentException("Failed to normalize URL");
        }
    }

    /**
     * 仅允许公网地址。屏蔽 loopback/link-local/site-local/多播/保留/文档网段等。
     */
    private static boolean isPublicAddress(InetAddress address) {
        if (address.isAnyLocalAddress()
                || address.isLoopbackAddress()
                || address.isLinkLocalAddress()
                || address.isSiteLocalAddress()
                || address.isMulticastAddress()) {
            return false;
        }

        byte[] bytes = address.getAddress();

        // IPv4
        if (bytes.length == 4) {
            int b0 = bytes[0] & 0xFF;
            int b1 = bytes[1] & 0xFF;
            int b2 = bytes[2] & 0xFF;
            int b3 = bytes[3] & 0xFF;

            // 0.0.0.0/8
            if (b0 == 0) return false;
            // 10.0.0.0/8
            if (b0 == 10) return false;
            // 127.0.0.0/8
            if (b0 == 127) return false;
            // 169.254.0.0/16
            if (b0 == 169 && b1 == 254) return false;
            // 172.16.0.0/12
            if (b0 == 172 && (b1 >= 16 && b1 <= 31)) return false;
            // 192.168.0.0/16
            if (b0 == 192 && b1 == 168) return false;
            // 100.64.0.0/10 (CGNAT)
            if (b0 == 100 && (b1 >= 64 && b1 <= 127)) return false;
            // 192.0.0.0/24
            if (b0 == 192 && b1 == 0 && b2 == 0) return false;
            // 192.0.2.0/24 (TEST-NET-1)
            if (b0 == 192 && b1 == 0 && b2 == 2) return false;
            // 192.88.99.0/24 (6to4 Anycast)
            if (b0 == 192 && b1 == 88 && b2 == 99) return false;
            // 198.18.0.0/15 (benchmark)
            if (b0 == 198 && (b1 == 18 || b1 == 19)) return false;
            // 198.51.100.0/24 (TEST-NET-2)
            if (b0 == 198 && b1 == 51 && b2 == 100) return false;
            // 203.0.113.0/24 (TEST-NET-3)
            if (b0 == 203 && b1 == 0 && b2 == 113) return false;
            // 224.0.0.0/4 (multicast) and 240.0.0.0/4 (reserved)
            if (b0 >= 224) return false;
            // 255.255.255.255 broadcast
            if (b0 == 255 && b1 == 255 && b2 == 255 && b3 == 255) return false;

            return true;
        }

        // IPv6
        if (bytes.length == 16) {
            // ::/128 unspecified handled by isAnyLocalAddress()
            // ::1/128 loopback handled by isLoopbackAddress()
            // fe80::/10 link-local handled by isLinkLocalAddress()
            // fc00::/7 unique local
            int first = bytes[0] & 0xFF;
            if ((first & 0xFE) == 0xFC) {
                return false; // fc00::/7
            }
            // ff00::/8 multicast handled by isMulticastAddress()
            if (first == 0xFF) {
                return false;
            }
            // 2001:db8::/32 (documentation)
            if ((bytes[0] & 0xFF) == 0x20 && (bytes[1] & 0xFF) == 0x01
                    && (bytes[2] & 0xFF) == 0x0D && (bytes[3] & 0xFF) == 0xB8) {
                return false;
            }
            // 2001:0::/32 (Teredo)
            if ((bytes[0] & 0xFF) == 0x20 && (bytes[1] & 0xFF) == 0x01
                    && (bytes[2] & 0xFF) == 0x00 && (bytes[3] & 0xFF) == 0x00) {
                return false;
            }
            // 2002::/16 (6to4)
            if ((bytes[0] & 0xFF) == 0x20 && (bytes[1] & 0xFF) == 0x02) {
                return false;
            }
            // Site-local (deprecated) might not be flagged by isSiteLocal for IPv6 on all JVMs, check again
            if (address instanceof Inet6Address) {
                Inet6Address a6 = (Inet6Address) address;
                if (a6.isMCGlobal() || a6.isMCSiteLocal() || a6.isMCOrgLocal() || a6.isMCNodeLocal() || a6.isMCLinkLocal()) {
                    return false;
                }
            }
            return true;
        }

        // 未知地址族，拒绝
        return false;
    }

    /**
     * 自定义安全DNS解析器：仅返回公共IP地址，若全为非公网地址则抛出 UnknownHostException。
     * 这样可防止DNS重绑定至内网地址。
     */
    private static class SafeDnsResolver implements DnsResolver {
        @Override
        public InetAddress[] resolve(String host) throws UnknownHostException {
            String asciiHost = IDN.toASCII(host, IDN.ALLOW_UNASSIGNED);
            InetAddress[] all = InetAddress.getAllByName(asciiHost);
            return Arrays.stream(all)
                    .filter(WebPageFetcherService::isPublicAddress)
                    .toArray(InetAddress[]::new);
        }
    }
}

