/**
 * 提供从Web上获取页面内容的服务（修复SSRF漏洞并强化健壮性）。
 * 关键安全点：
 * 1) 仅允许 http/https 协议，禁止携带用户凭证（userinfo）。
 * 2) 解析并校验目标主机所有解析得到的IP，禁止访问内网、环回、链路本地、组播、保留地址等。
 * 3) 禁止自动跟随重定向，避免通过重定向命中内网。
 * 4) 限制可访问的端口为常见Web端口，防止非常规端口攻击。
 * 5) 设置连接/读取超时，限制响应最大字节，防止资源消耗攻击。
 */
@Service
public class WebPageFetcherService {

    // 允许的端口（可按需扩展或改为白名单域名）
    private static final Set<Integer> ALLOWED_PORTS = new HashSet<>(Arrays.asList(80, 443, 8080, 8443));
    // 读取的最大响应体字节数，防止大响应导致内存压力（可根据需求调整）
    private static final long MAX_RESPONSE_BYTES = 2L * 1024 * 1024; // 2 MB
    // 连接与读取超时（毫秒）
    private static final int CONNECT_TIMEOUT_MS = 5000;
    private static final int READ_TIMEOUT_MS = 10000;

    private final RestTemplate secureRestTemplate;

    @Autowired
    public WebPageFetcherService(RestTemplate restTemplate) {
        // 基于注入的 RestTemplate 复制转换器/拦截器，但使用自定义的 RequestFactory 禁用重定向并设置超时
        this.secureRestTemplate = new RestTemplate();
        this.secureRestTemplate.setMessageConverters(restTemplate.getMessageConverters());
        this.secureRestTemplate.setInterceptors(restTemplate.getInterceptors());

        SimpleClientHttpRequestFactory factory = new SimpleClientHttpRequestFactory() {
            @Override
            protected void prepareConnection(HttpURLConnection connection, String httpMethod) throws IOException {
                super.prepareConnection(connection, httpMethod);
                // 禁止自动跟随重定向，避免经由外部网站重定向到内网地址
                connection.setInstanceFollowRedirects(false);
            }
        };
        // 设置超时
        factory.setConnectTimeout(CONNECT_TIMEOUT_MS);
        factory.setReadTimeout(READ_TIMEOUT_MS);

        this.secureRestTemplate.setRequestFactory(factory);
    }

    /**
     * 根据提供的URL获取其HTML页面内容。
     * 该方法设计用于从公共互联网获取数据。
     *
     * @param url 输入的完整URL，例如 "https://www.example.com"
     * @return 返回网页的HTML内容字符串。如果无法访问或发生错误，则返回null。
     */
    public String getPageContent(String url) {
        try {
            URI uri = validateAndNormalizeUrl(url);

            // 只允许 GET 请求，设置基础的 Accept 和 UA
            RequestCallback requestCallback = request -> {
                request.getHeaders().setAccept(Arrays.asList(
                        MediaType.TEXT_HTML,
                        MediaType.TEXT_PLAIN,
                        MediaType.valueOf("application/xhtml+xml")
                ));
                request.getHeaders().set(HttpHeaders.USER_AGENT, "WebPageFetcher/1.0 (+security-ssrf-protected)");
            };

            ResponseExtractor<String> responseExtractor = response -> {
                // 基于 Content-Length 快速校验
                Long length = response.getHeaders().getContentLength();
                if (length != null && length > 0 && length > MAX_RESPONSE_BYTES) {
                    throw new IOException("Response too large: " + length + " bytes");
                }
                InputStream body = response.getBody();
                if (body == null) {
                    return null;
                }
                ByteArrayOutputStream baos = new ByteArrayOutputStream();
                byte[] buffer = new byte[8192];
                long total = 0;
                int n;
                while ((n = body.read(buffer)) != -1) {
                    total += n;
                    if (total > MAX_RESPONSE_BYTES) {
                        throw new IOException("Response exceeded max allowed size: " + MAX_RESPONSE_BYTES);
                    }
                    baos.write(buffer, 0, n);
                }
                Charset charset = StandardCharsets.UTF_8;
                MediaType contentType = response.getHeaders().getContentType();
                if (contentType != null && contentType.getCharset() != null) {
                    charset = contentType.getCharset();
                }
                return baos.toString(charset);
            };

            return secureRestTemplate.execute(uri, HttpMethod.GET, requestCallback, responseExtractor);
        } catch (Exception e) {
            // 在实际应用中，建议使用日志框架记录详细信息（包含堆栈与上下文）
            System.err.println("Error fetching content from URL: " + url + " - " + e.getMessage());
            return null;
        }
    }

    // 解析、标准化并校验URL
    private URI validateAndNormalizeUrl(String input) throws URISyntaxException, UnknownHostException {
        if (input == null) {
            throw new URISyntaxException("null", "URL must not be null");
        }
        URI uri = new URI(input.trim()).normalize();

        if (!uri.isAbsolute()) {
            throw new URISyntaxException(input, "URL must be absolute");
        }
        String scheme = uri.getScheme();
        if (scheme == null) {
            throw new URISyntaxException(input, "URL must have a scheme");
        }
        String schemeLower = scheme.toLowerCase(Locale.ROOT);
        if (!("http".equals(schemeLower) || "https".equals(schemeLower))) {
            throw new URISyntaxException(input, "Only http/https schemes are allowed");
        }
        if (uri.getUserInfo() != null) {
            throw new URISyntaxException(input, "Userinfo in URL is not allowed");
        }
        String host = uri.getHost();
        if (host == null || host.isEmpty()) {
            throw new URISyntaxException(input, "Host is required");
        }
        String hostLower = host.toLowerCase(Locale.ROOT);
        if ("localhost".equals(hostLower) || hostLower.endsWith(".localhost")) {
            throw new URISyntaxException(input, "Access to localhost is not allowed");
        }

        int port = uri.getPort();
        int effectivePort = (port == -1) ? defaultPortForScheme(schemeLower) : port;
        if (!ALLOWED_PORTS.contains(effectivePort)) {
            throw new URISyntaxException(input, "Port " + effectivePort + " is not allowed");
        }

        // 解析所有IP并校验，防止DNS解析到内网地址或保留地址（含IPv6）
        InetAddress[] addresses = InetAddress.getAllByName(host);
        if (addresses == null || addresses.length == 0) {
            throw new UnknownHostException("No addresses resolved for host " + host);
        }
        for (InetAddress addr : addresses) {
            if (isBlockedAddress(addr)) {
                throw new URISyntaxException(input, "Resolved to a forbidden address: " + addr.getHostAddress());
            }
        }

        // 重新构造URI（移除片段等），避免一些奇异输入
        try {
            return new URI(
                    schemeLower,
                    null,                 // userInfo 禁止
                    host,                 // host
                    port,                 // 原始端口（如为-1保留-1）
                    uri.getPath(),
                    uri.getQuery(),
                    null                  // fragment 去除
            ).normalize();
        } catch (URISyntaxException ex) {
            // 回退使用原始标准化URI（已校验）
            return uri;
        }
    }

    private static int defaultPortForScheme(String schemeLower) {
        return "https".equals(schemeLower) ? 443 : 80;
    }

    private static boolean isBlockedAddress(InetAddress addr) {
        // 通用快速判断
        if (addr.isAnyLocalAddress()           // 0.0.0.0 / ::
                || addr.isLoopbackAddress()    // 127.0.0.1 / ::1
                || addr.isLinkLocalAddress()   // 169.254.0.0/16 / fe80::/10
                || addr.isSiteLocalAddress()   // 私有网段 10/8、172.16/12、192.168/16 或 fec0::/10(已废弃但仍视为站点本地)
                || addr.isMulticastAddress()) { // 224.0.0.0/4 / ff00::/8
            return true;
        }

        // 进一步的IPv4保留与共享地址段拦截
        if (addr instanceof Inet4Address) {
            int ip = ipv4ToInt(addr.getAddress());

            // 额外拦截的IPv4网段：
            // 0.0.0.0/8、100.64.0.0/10（共享地址）、169.254.0.0/16（链路本地，已被上面拦截，但冗余无妨）、
            // 192.0.0.0/24（IETF保留）、198.18.0.0/15（网络基准测试）、224.0.0.0/4（组播）、240.0.0.0/4（保留）
            if (inRange(ip, ipv4Cidr("0.0.0.0"), 8)
                    || inRange(ip, ipv4Cidr("100.64.0.0"), 10)
                    || inRange(ip, ipv4Cidr("169.254.0.0"), 16)
                    || inRange(ip, ipv4Cidr("192.0.0.0"), 24)
                    || inRange(ip, ipv4Cidr("198.18.0.0"), 15)
                    || inRange(ip, ipv4Cidr("224.0.0.0"), 4)
                    || inRange(ip, ipv4Cidr("240.0.0.0"), 4)) {
                return true;
            }
        }

        // 进一步的IPv6 ULA（fc00::/7）拦截
        if (addr instanceof Inet6Address) {
            byte[] b = addr.getAddress();
            // fc00::/7 => 前7位为 1111110x，因此 b[0] & 0xFE == 0xFC
            if ((b[0] & (byte) 0xFE) == (byte) 0xFC) {
                return true;
            }
        }

        return false;
    }

    // IPv4工具函数
    private static int ipv4ToInt(byte[] bytes) {
        return ((bytes[0] & 0xFF) << 24)
                | ((bytes[1] & 0xFF) << 16)
                | ((bytes[2] & 0xFF) << 8)
                | (bytes[3] & 0xFF);
    }

    private static int ipv4Cidr(String dotted) {
        String[] parts = dotted.split("\\.");
        return ((Integer.parseInt(parts[0]) & 0xFF) << 24)
                | ((Integer.parseInt(parts[1]) & 0xFF) << 16)
                | ((Integer.parseInt(parts[2]) & 0xFF) << 8)
                | (Integer.parseInt(parts[3]) & 0xFF);
    }

    private static boolean inRange(int ip, int network, int prefix) {
        if (prefix <= 0) {
            return true;
        }
        int mask = prefix == 32 ? 0xFFFFFFFF : (-1 << (32 - prefix));
        return (ip & mask) == (network & mask);
        // 注意：Java int为有符号，但按位与比较在此场景下可行
    }
}

