        if (inRange(ip, ip(172, 16, 0, 0), ip(172, 31, 255, 255))) return false;
        if (inRange(ip, ip(192, 168, 0, 0), ip(192, 168, 255, 255))) return false;
        if (inRange(ip, ip(169, 254, 0, 0), ip(169, 254, 255, 255))) return false;
        if (inRange(ip, ip(100, 64, 0, 0), ip(100, 127, 255, 255))) return false;
        if (inRange(ip, ip(192, 0, 0, 0), ip(192, 0, 0, 255))) return false;
        if (inRange(ip, ip(192, 0, 2, 0), ip(192, 0, 2, 255))) return false;
        if (inRange(ip, ip(198, 51, 100, 0), ip(198, 51, 100, 255))) return false;
        if (inRange(ip, ip(203, 0, 113, 0), ip(203, 0, 113, 255))) return false;
        if (inRange(ip, ip(198, 18, 0, 0), ip(198, 19, 255, 255))) return false;
        if (inRange(ip, ip(240, 0, 0, 0), ip(255, 255, 255, 254))) return false;
        return true;
    }

    private static int ipv4ToInt(Inet4Address a) {
        byte[] b = a.getAddress();
        return ((b[0] & 0xFF) << 24) | ((b[1] & 0xFF) << 16) | ((b[2] & 0xFF) << 8) | (b[3] & 0xFF);
    }

    private static boolean inRange(int ip, int start, int end) {
        long x = ip & 0xFFFFFFFFL;
        long s = start & 0xFFFFFFFFL;
        long e = end & 0xFFFFFFFFL;
        return x >= s && x <= e;
    }

    private static int ip(int a, int b, int c, int d) {
        return (a << 24) | (b << 16) | (c << 8) | d;
    }

    // 用于封装受限读取后的响应结果
    private static final class LimitedResponse {
        final HttpStatus status;
        final HttpHeaders headers;
        final byte[] body;

        LimitedResponse(HttpStatus status, HttpHeaders headers, byte[] body) {
            this.status = status;
            this.headers = headers;
            this.body = body;
        }
    }

    // 自定义DNS解析器：仅返回通过公网校验的地址，否则抛出 UnknownHostException 阻断请求
    private static final class SafeDnsResolver implements DnsResolver {
        @Override
        public InetAddress[] resolve(String host) throws UnknownHostException {
            if (host == null || host.isEmpty()) {
                throw new UnknownHostException("Empty host");
            }
            String ascii = IDN.toASCII(host, IDN.ALLOW_UNASSIGNED);
            InetAddress[] all = InetAddress.getAllByName(ascii);
            // 过滤，仅允许公网地址
            int count = 0;
            for (InetAddress a : all) {
                if (isPublicAddress(a)) count++;
                else {
                    // 一旦检测到非公网地址，直接拒绝，避免多记录中的私网地址被选中
                    throw new UnknownHostException("Blocked non-public address for host: " + host + " -> " + a.getHostAddress());
