    private static boolean isGlobalUnicastAddress(InetAddress address) {
        if (address.isAnyLocalAddress()) return false;      // 0.0.0.0 / ::
        if (address.isLoopbackAddress()) return false;       // 127.0.0.1 / ::1
        if (address.isLinkLocalAddress()) return false;      // 169.254.0.0/16, fe80::/10
        if (address.isSiteLocalAddress()) return false;      // 10/8, 172.16/12, 192.168/16
        if (address.isMulticastAddress()) return false;      // 224.0.0.0/4, ff00::/8

        byte[] bytes = address.getAddress();

        if (address instanceof Inet4Address) {
            int b0 = bytes[0] & 0xFF;
            int b1 = bytes[1] & 0xFF;

            // 0.0.0.0/8
            if (b0 == 0) return false;

            // 100.64.0.0/10 (CGNAT)
            if ((b0 == 100) && ((b1 & 0xC0) == 0x40)) return false;

            // 127.0.0.0/8（已由isLoopback覆盖，这里保险）
            if (b0 == 127) return false;

            // 169.254.0.0/16（已由isLinkLocal覆盖）
            if (b0 == 169 && b1 == 254) return false;

            // 192.0.0.0/24，包括192.0.2.0/24 TEST-NET-1
            if (b0 == 192 && b1 == 0) return false;

            // 198.18.0.0/15 (benchmark)
            if (b0 == 198 && (b1 == 18 || b1 == 19)) return false;

            // 198.51.100.0/24 TEST-NET-2
            if (b0 == 198 && b1 == 51) return false;

            // 203.0.113.0/24 TEST-NET-3
            if (b0 == 203 && b1 == 0) return false;

            // 224.0.0.0/4 多播（已由isMulticast覆盖）

            // 240.0.0.0/4 保留
            if ((b0 & 0xF0) == 0xF0) return false;

            // 255.255.255.255 广播
            if (b0 == 255 && (bytes[1] & 0xFF) == 255 && (bytes[2] & 0xFF) == 255 && (bytes[3] & 0xFF) == 255) {
                return false;
            }

            return true;
        } else {
            // IPv6
            // ::/128 未指定（已由isAnyLocalAddress覆盖）
            // ::1/128 回环（已由isLoopback覆盖）
            // fe80::/10 链路本地（已由isLinkLocal覆盖）
            // fc00::/7 唯一本地地址（ULA）
            if (isInIpv6Prefix(bytes, hexToBytes("fc00"), 7)) return false;

            // 2001:db8::/32 文档前缀
            if (isInIpv6Prefix(bytes, hexToBytes("20010db8"), 32)) return false;

            // ::ffff:0:0/96 IPv4映射地址，取出映射的IPv4再判断
            if (isInIpv6Prefix(bytes, hexToBytes("00000000000000000000ffff"), 96)) {
                byte[] v4 = Arrays.copyOfRange(bytes, 12, 16);
                try {
                    return isGlobalUnicastAddress(InetAddress.getByAddress(v4));
                } catch (UnknownHostException ignored) {
                    return false;
                }
            }

            // 多播 ff00::/8（已由isMulticast覆盖）

            return true;
        }
    }

    // 判断IPv6前缀匹配
    private static boolean isInIpv6Prefix(byte[] addr, byte[] prefix, int prefixLen) {
        // prefix 是以网络序拼接的前缀字节序列
        int fullBytes = prefixLen / 8;
        int remBits = prefixLen % 8;

        for (int i = 0; i < fullBytes; i++) {
            if (addr[i] != prefix[i]) return false;
        }
        if (remBits == 0) return true;

        int mask = 0xFF << (8 - remBits);
        return (addr[fullBytes] & mask) == (prefix[fullBytes] & mask);
    }

    // 将十六进制字符串（不含冒号）转为字节数组（用于前缀匹配）
    private static byte[] hexToBytes(String hex) {
        String h = hex;
        if ((h.length() & 1) == 1) h = "0" + h;
        byte[] out = new byte[h.length() / 2];
        for (int i = 0; i < out.length; i++) {
            int hi = Character.digit(h.charAt(i * 2), 16);
            int lo = Character.digit(h.charAt(i * 2 + 1), 16);
            out[i] = (byte) ((hi << 4) | lo);
        }
        // 补足到16字节，便于统一处理
        if (out.length < 16) {
            byte[] full = new byte[16];
            System.arraycopy(out, 0, full, 0, out.length);
            return full;
        }
        return out;
    }
}

