    private static final Set<String> ALLOWED_SCHEMES = Set.of("http", "https");
    private static final int HTTP_PORT = 80;
    private static final int HTTPS_PORT = 443;

    // 超时与限制
    private static final int CONNECT_TIMEOUT_MS = 5000;
    private static final int READ_TIMEOUT_MS = 8000;
    private static final int MAX_REDIRECTS = 5;
    private static final int MAX_RESPONSE_BYTES = 1_000_000; // 最大读取1MB
    private static final Set<String> ALLOWED_CONTENT_TYPES = Set.of(
            "text/html",
            "application/xhtml+xml"
    );

    private final RestTemplate safeRestTemplate;

    @Autowired
    public WebPageFetcherService(RestTemplate baseRestTemplate) {
        // 基于 Apache HttpClient 构建带有DNS过滤和重定向校验的 RestTemplate，
        // 避免修改全局注入的 RestTemplate Bean。
        this.safeRestTemplate = createSafeRestTemplate(baseRestTemplate);
