                InetAddress addr = InetAddress.getByName(host);
                if (!isPublicInetAddress(addr)) {
                    throw new URISyntaxException(url, "Target IP not publicly routable");
                }
            } catch (UnknownHostException e) {
                throw new URISyntaxException(url, "Invalid IP literal");
            }
        }

        return raw;
    }

    private static boolean isAllowedPort(String scheme, int port) {
        if ("http".equals(scheme)) {
            return port == -1 || port == HTTP_PORT;
        } else if ("https".equals(scheme)) {
            return port == -1 || port == HTTPS_PORT;
        }
        return false;
