    private static boolean isAllowedContentType(String baseType) {
        // 仅允许html相关类型
        return ALLOWED_CONTENT_TYPES.contains(baseType.toLowerCase(Locale.ROOT));
    }

    private static Charset resolveCharset(HttpHeaders headers, MediaType mediaType) throws IOException {
        // 优先使用Content-Type中的charset，没有则回退到UTF-8
        if (mediaType != null && mediaType.getCharset() != null) {
            return mediaType.getCharset();
        }
        // 也可解析Content-Type原始值
        List<String> raw = headers.get(HttpHeaders.CONTENT_TYPE);
        if (raw != null) {
