            // 0.0.0.0/8
            if (inRange(ip, ipv4ToInt(new byte[]{0, 0, 0, 0}), 8)) return false;
            // 255.255.255.255/32 (广播)
            if (ip == 0xFFFFFFFF) return false;
            // 169.254.169.254 (云环境元数据) -> 已被 169.254/16 覆盖，但显式强调
            int meta = ipv4ToInt(new byte[]{(byte) 169, (byte) 254, (byte) 169, (byte) 254});
            if (ip == meta) return false;
        } else {
            // IPv6 额外禁止的范围：ULA fc00::/7、文档前缀 2001:db8::/32
            if (isIpv6InPrefix(addr, "fc00::", 7)) return false;      // 唯一本地地址
            if (isIpv6InPrefix(addr, "2001:db8::", 32)) return false; // 文档专用前缀
        }

        return true;
    }

    private static InputStream safeInputStream(HttpURLConnection conn) {
        try {
            InputStream in = conn.getInputStream();
            if (in != null) return in;
        } catch (Exception ignore) {
        }
        try {
            return conn.getErrorStream();
        } catch (Exception e) {
            return null;
        }
    }

    private static byte[] readUpTo(InputStream in, int maxBytes) throws Exception {
        ByteArrayOutputStream bos = new ByteArrayOutputStream(Math.min(8192, maxBytes));
        byte[] buf = new byte[8192];
        int remaining = maxBytes;
        int read;
        while (remaining > 0 && (read = in.read(buf, 0, Math.min(buf.length, remaining))) != -1) {
            bos.write(buf, 0, read);
            remaining -= read;
