    }

    private static String lower(String s) {
        return s == null ? null : s.toLowerCase(Locale.ROOT);
    }

    private static int ipv4ToInt(byte[] addr) {
        // addr.length == 4
        return ((addr[0] & 0xFF) << 24)
                | ((addr[1] & 0xFF) << 16)
                | ((addr[2] & 0xFF) << 8)
                | (addr[3] & 0xFF);
    }

    private static boolean inRange(int ip, int network, int prefixLen) {
        int mask = prefixLen == 0 ? 0 : 0xFFFFFFFF << (32 - prefixLen);
        return (ip & mask) == (network & mask);
    }

    private static boolean isIpv6InPrefix(InetAddress addr, String prefix, int prefixLen) {
        try {
            byte[] address = addr.getAddress();
            byte[] network = InetAddress.getByName(prefix).getAddress();
            int fullBytes = prefixLen / 8;
            int remainingBits = prefixLen % 8;

            for (int i = 0; i < fullBytes; i++) {
                if (address[i] != network[i]) return false;
            }
            if (remainingBits == 0) return true;
            int mask = 0xFF << (8 - remainingBits);
            return (address[fullBytes] & mask) == (network[fullBytes] & mask);
        } catch (Exception e) {
            return false;
        }
    }
}

