import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpMethod;
import org.springframework.http.MediaType;
import org.springframework.http.client.SimpleClientHttpRequestFactory;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestClientException;
import org.springframework.web.client.RestTemplate;

import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.net.IDN;
import java.net.Inet4Address;
import java.net.Inet6Address;
import java.net.InetAddress;
import java.net.URI;
import java.net.URISyntaxException;
import java.nio.charset.Charset;
import java.nio.charset.StandardCharsets;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

/**
 * 提供从Web上获取页面内容的服务（已加固，避免SSRF）。
 * 主要防护措施：
 * 1) 仅允许 http/https 协议及 80/443 端口
 * 2) 禁止携带用户信息（如 http://user@host/）
 * 3) 解析目标主机的所有IP，禁止访问内网/回环/链路本地/保留地址（IPv4/IPv6）
 * 4) 禁止自动跟随重定向（默认 JDK 实现已禁用）
 * 5) 限制连接和读取超时，限制最大响应体大小
 * 6) 限制 Content-Type 为文本/HTML 类内容
 */
@Service
public class WebPageFetcherService {

    private static final Logger log = LoggerFactory.getLogger(WebPageFetcherService.class);

    private static final Set<String> ALLOWED_SCHEMES = new HashSet<>(Arrays.asList("http", "https"));
    private static final Set<Integer> ALLOWED_PORTS = new HashSet<>(Arrays.asList(80, 443));

    private static final int CONNECT_TIMEOUT_MS = 5000;
    private static final int READ_TIMEOUT_MS = 10000;
    private static final int MAX_RESPONSE_BYTES = 1_000_000; // 1MB

    private final RestTemplate baseRestTemplate;

    @Autowired
    public WebPageFetcherService(RestTemplate restTemplate) {
        this.baseRestTemplate = restTemplate;
    }

    /**
     * 根据提供的URL获取其HTML页面内容。
     * 该方法设计用于从公共互联网获取数据。
     *
     * @param url 目标网页的完整URL，例如 "https://www.example.com"
     * @return 返回网页的HTML内容字符串。如果无法访问或发生错误，则返回null。
     */
    public String getPageContent(String url) {
        URI inputUri;
        try {
            inputUri = new URI(url);
        } catch (URISyntaxException e) {
            log.warn("Invalid URL syntax: {}", url, e);
            return null;
        }

        // 1) 协议白名单
        String scheme = inputUri.getScheme();
        if (scheme == null || !ALLOWED_SCHEMES.contains(scheme.toLowerCase())) {
            log.warn("Blocked by scheme: {}", url);
            return null;
        }

        // 2) 禁止用户信息
        if (inputUri.getUserInfo() != null) {
            log.warn("Blocked due to user info in URL: {}", url);
            return null;
        }

        // 3) 端口白名单（若未指定端口则使用默认端口）
        int port = inputUri.getPort();
        int effectivePort = (port == -1) ? defaultPortForScheme(scheme) : port;
        if (!ALLOWED_PORTS.contains(effectivePort)) {
            log.warn("Blocked by disallowed port {} for URL: {}", effectivePort, url);
            return null;
        }

        // 4) 主机校验与解析，阻断内网/回环等地址
        String host = inputUri.getHost();
        if (host == null || host.isEmpty()) {
            log.warn("No host in URL: {}", url);
            return null;
        }

        // 统一为 ASCII（支持国际化域名）
        String asciiHost;
        try {
            asciiHost = IDN.toASCII(host);
        } catch (IllegalArgumentException e) {
            log.warn("Invalid IDN host: {}", host, e);
            return null;
        }

        // 明确阻断常见本地域名
        if (isBlockedHostName(asciiHost)) {
            log.warn("Blocked host name: {}", asciiHost);
            return null;
        }

        // 解析所有地址并校验是否为公网地址
        try {
            validateResolvedAddresses(asciiHost);
        } catch (Exception e) {
            log.warn("Blocked by address validation for host {} (from URL {}): {}", asciiHost, url, e.toString());
            return null;
        }

        // 5) 规范化URI（将主机替换为ASCII形式；保留原路径/查询/片段）
        URI normalizedUri;
        try {
            normalizedUri = new URI(
                    scheme,
                    null, // 已禁止 userInfo
                    asciiHost,
                    (port == -1 ? -1 : effectivePort),
                    inputUri.getPath(),
                    inputUri.getQuery(),
                    inputUri.getFragment()
            );
        } catch (URISyntaxException e) {
            log.warn("Failed to normalize URL: {}", url, e);
            return null;
        }

        // 6) 使用带有超时配置且不自动重定向的 RestTemplate
        RestTemplate client = buildSafeRestTemplate();

        try {
            return client.execute(normalizedUri, HttpMethod.GET, request -> {
                HttpHeaders headers = request.getHeaders();
                headers.set(HttpHeaders.USER_AGENT, "WebPageFetcher/1.0 (+https://example.com)");
                headers.setAccept(Arrays.asList(MediaType.TEXT_HTML, MediaType.TEXT_PLAIN, MediaType.APPLICATION_XHTML_XML));
            }, response -> {
                if (!response.getStatusCode().is2xxSuccessful()) {
                    return null;
                }
                MediaType contentType = response.getHeaders().getContentType();
                if (!isAllowedContentType(contentType)) {
                    log.warn("Blocked by content-type {} from {}", contentType, normalizedUri);
                    return null;
                }

                InputStream in = response.getBody();
                if (in == null) {
                    return null;
                }

                ByteArrayOutputStream bos = new ByteArrayOutputStream(Math.min(64 * 1024, MAX_RESPONSE_BYTES));
                byte[] buf = new byte[8192];
                int total = 0;
                int n;
                while ((n = in.read(buf)) != -1) {
                    total += n;
                    if (total > MAX_RESPONSE_BYTES) {
                        log.warn("Response too large (>{} bytes) from {}", MAX_RESPONSE_BYTES, normalizedUri);
                        return null;
                    }
                    bos.write(buf, 0, n);
                }

                Charset charset = (contentType != null && contentType.getCharset() != null)
                        ? contentType.getCharset()
                        : StandardCharsets.UTF_8;

                return new String(bos.toByteArray(), charset);
            });
        } catch (RestClientException | IOException e) {
            log.warn("Error fetching content from URL: {}", normalizedUri, e);
            return null;
        }
    }

    private RestTemplate buildSafeRestTemplate() {
        // 基于注入的 RestTemplate 复制必要配置，但设置自己的超时与请求工厂
        RestTemplate rt = new RestTemplate();
        try {
            rt.setMessageConverters(baseRestTemplate.getMessageConverters());
        } catch (Exception ignored) {
        }
        try {
            rt.setInterceptors(baseRestTemplate.getInterceptors());
        } catch (Exception ignored) {
        }
        try {
            rt.setErrorHandler(baseRestTemplate.getErrorHandler());
        } catch (Exception ignored) {
        }

        // 默认的 SimpleClientHttpRequestFactory 已禁用自动跟随重定向
        SimpleClientHttpRequestFactory f = new SimpleClientHttpRequestFactory();
        f.setConnectTimeout(CONNECT_TIMEOUT_MS);
        f.setReadTimeout(READ_TIMEOUT_MS);
        rt.setRequestFactory(f);
        return rt;
    }

    private static int defaultPortForScheme(String scheme) {
        return "https".equalsIgnoreCase(scheme) ? 443 : 80;
    }

    private static boolean isAllowedContentType(MediaType contentType) {
        if (contentType == null) {
            // 未返回类型时放行（常见于部分站点），后续由读取逻辑限制大小
            return true;
        }
        String type = contentType.getType();
        String subtype = contentType.getSubtype();
        if (type == null || subtype == null) {
            return false;
        }
        type = type.toLowerCase();
        subtype = subtype.toLowerCase();

        // 允许 text/*，application/xhtml+xml，application/html
        if ("text".equals(type)) {
            return true;
        }
        if ("application".equals(type) && ("xhtml+xml".equals(subtype) || "html".equals(subtype))) {
            return true;
        }
        return false;
    }

    private static boolean isBlockedHostName(String host) {
        String h = host.toLowerCase();
        return "localhost".equals(h) || h.endsWith(".localhost") || "local".equals(h) || h.endsWith(".local");
    }

    private static void validateResolvedAddresses(String host) throws Exception {
        InetAddress[] addrs = InetAddress.getAllByName(host);
        if (addrs == null || addrs.length == 0) {
            throw new IllegalArgumentException("No addresses resolved");
        }
        for (InetAddress addr : addrs) {
            if (!isPublicAddress(addr)) {
                throw new IllegalArgumentException("Non-public address resolved: " + addr.getHostAddress());
            }
        }
    }

    private static boolean isPublicAddress(InetAddress addr) {
        // 通用阻断
        if (addr.isAnyLocalAddress()) return false;     // 0.0.0.0 / ::
        if (addr.isLoopbackAddress()) return false;     // 127.0.0.0/8 / ::1
        if (addr.isLinkLocalAddress()) return false;    // 169.254.0.0/16 / fe80::/10
        if (addr.isSiteLocalAddress()) return false;    // 10/8, 172.16/12, 192.168/16, (IPv6 旧 site-local)
        if (addr.isMulticastAddress()) return false;    // 224.0.0.0/4 / ff00::/8

        // 额外IPv4网段
        if (addr instanceof Inet4Address) {
            byte[] b = addr.getAddress();
            int b0 = b[0] & 0xFF;
            int b1 = b[1] & 0xFF;

            // 0.0.0.0/8
            if (b0 == 0) return false;

            // 100.64.0.0/10 (CGNAT)
            if (b0 == 100 && (b1 >= 64 && b1 <= 127)) return false;

            // 169.254.0.0/16 (link-local) 已由 isLinkLocalAddress 处理，但再次防护
            if (b0 == 169 && b1 == 254) return false;

            // 192.0.0.0/24（IETF协议保留）
            if (b0 == 192 && b1 == 0) return false;

            // 240.0.0.0/4（保留/实验）
            if (b0 >= 240) return false;
        }

        // 额外IPv6网段
        if (addr instanceof Inet6Address) {
            Inet6Address a6 = (Inet6Address) addr;
            byte[] b = a6.getAddress();

            // IPv4-mapped IPv6 ::ffff:0:0/96
            if (isIPv4Mapped(a6)) {
                byte[] v4 = Arrays.copyOfRange(b, 12, 16);
                try {
                    return isPublicAddress(Inet4Address.getByAddress(v4));
                } catch (Exception e) {
                    return false;
                }
            }

            // fc00::/7 (Unique local addresses, ULA)
            int first = b[0] & 0xFF;
            if ((first & 0xFE) == 0xFC) {
                return false;
            }

            // fe80::/10（link-local）已由 isLinkLocalAddress 处理
            // 2001:db8::/32（文档网段）不可达，视为非公网
            if ((first == 0x20) && (b[1] == (byte) 0x01) && (b[2] == (byte) 0x0D) && (b[3] == (byte) 0xB8)) {
                return false;
            }
        }

        // 其它情况视为可公开访问
        return true;
    }

    private static boolean isIPv4Mapped(Inet6Address addr) {
        byte[] b = addr.getAddress();
        for (int i = 0; i < 10; i++) {
            if (b[i] != 0x00) return false;
        }
        return (b[10] == (byte) 0xFF) && (b[11] == (byte) 0xFF);
    }
}

