            if (isInIpv4Range(b, "192.88.99.0", 24)) return false;      // 6to4 任何播
            if (isInIpv4Range(b, "192.168.0.0", 16)) return false;      // 私有
            if (isInIpv4Range(b, "198.18.0.0", 15)) return false;       // 基准测试
            if (isInIpv4Range(b, "198.51.100.0", 24)) return false;     // TEST-NET-2
            if (isInIpv4Range(b, "203.0.113.0", 24)) return false;      // TEST-NET-3
            if (isInIpv4Range(b, "224.0.0.0", 4)) return false;         // 组播（已由 isMulticastAddress 排除）
            if (isInIpv4Range(b, "240.0.0.0", 4)) return false;         // 预留
            return true;
        }

        return false;
    }

    private boolean isIPv6UniqueLocal(Inet6Address addr) {
        byte[] b = addr.getAddress();
        // fc00::/7 -> 0b11111100 (0xFC) with mask 0b11111110 (0xFE)
        return (b[0] & (byte) 0xFE) == (byte) 0xFC;
