    private boolean isInIpv6Range(Inet6Address addr, String base, int prefixLen) {
        try {
            Inet6Address baseAddr = (Inet6Address) InetAddress.getByName(base);
            byte[] a = addr.getAddress();
            byte[] b = baseAddr.getAddress();

            int fullBytes = prefixLen / 8;
            int remBits = prefixLen % 8;

            for (int i = 0; i < fullBytes; i++) {
                if (a[i] != b[i]) return false;
            }
            if (remBits == 0) return true;

            int mask = 0xFF << (8 - remBits);
            return (a[fullBytes] & mask) == (b[fullBytes] & mask);
        } catch (Exception e) {
            return false;
        }
    }

    private boolean isInIpv4Range(byte[] address, String cidrBase, int prefixLen) {
        try {
            InetAddress base = InetAddress.getByName(cidrBase);
            byte[] baseBytes = base.getAddress();
            if (!(base instanceof Inet4Address) || address.length != 4) {
                return false;
            }
            int addrInt = ByteBuffer.wrap(address).getInt();
            int baseInt = ByteBuffer.wrap(baseBytes).getInt();

            int mask = prefixLen == 0 ? 0 : -1 << (32 - prefixLen);
            return (addrInt & mask) == (baseInt & mask);
        } catch (Exception e) {
            return false;
        }
    }

    /**
     * 自定义安全DNS解析器：仅返回公网可路由地址，丢弃其他地址以防止 DNS Rebinding 到内网。
     */
    private class SafePublicDnsResolver implements DnsResolver {
        @Override
        public InetAddress[] resolve(String host) throws UnknownHostException {
            String asciiHost = IDN.toASCII(host);
            InetAddress[] all = InetAddress.getAllByName(asciiHost);
            List<InetAddress> allowed = new ArrayList<>(all.length);
            for (InetAddress a : all) {
                if (isPublicRoutableAddress(a)) {
                    allowed.add(a);
                }
            }
            if (allowed.isEmpty()) {
                throw new UnknownHostException("All resolved addresses are non-public for host: " + host);
            }
            return allowed.toArray(new InetAddress[0]);
        }
    }
}

