                || addr.isSiteLocalAddress()
                || addr.isMulticastAddress()
                || isUniqueLocalIPv6(addr)
                || isPrivateIPv4(addr);
    }

    private boolean isPrivateIPv4(InetAddress addr) {
        if (!(addr instanceof Inet4Address)) return false;
