    }

    private boolean isUniqueLocalIPv6(InetAddress addr) {
        if (!(addr instanceof Inet6Address)) return false;
        byte[] b = addr.getAddress();
        int first = b[0] & 0xFF;
        // fc00::/7 -> 0b11111100 (0xFC) or 0b11111101 (0xFD)
        return (first & 0xFE) == 0xFC;
    }
}

