            addresses = InetAddress.getAllByName(asciiHost);
        } catch (IOException e) {
            throw new IllegalArgumentException("DNS resolution failed for host: " + asciiHost);
        }
        if (addresses.length == 0) {
            throw new IllegalArgumentException("No IP address found for host: " + asciiHost);
        }
