            if (!isPublicIPAddress(addr)) {
                throw new IllegalArgumentException("Target host resolves to a non-public IP");
            }
        }
    }

    private static boolean isPublicIPAddress(InetAddress addr) {
        // 通用快速检查
        if (addr.isAnyLocalAddress() ||
            addr.isLoopbackAddress() ||
            addr.isLinkLocalAddress() ||
            addr.isSiteLocalAddress() ||
            addr.isMulticastAddress()) {
            return false;
        }

        byte[] b = addr.getAddress();

        // IPv6: 局域唯一地址 fc00::/7，未指定地址 ::/128，环回 ::1 已在上面覆盖
        if (addr instanceof Inet6Address) {
            int first = b[0] & 0xFF;
