            if ((first & 0xFE) == 0xFC) {
                return false;
            }
            // 2001:db8::/32 文档前缀也不应访问
            if (first == 0x20 && (b[1] & 0xFF) == 0x01 && (b[2] & 0xFF) == 0x0D && (b[3] & 0xFF) == 0xB8) {
                return false;
            }
            return true;
        }

        // IPv4 细分私网/保留段
        int b0 = b[0] & 0xFF;
        int b1 = b[1] & 0xFF;

        // 0.0.0.0/8
        if (b0 == 0) return false;
        // 10.0.0.0/8
        if (b0 == 10) return false;
        // 100.64.0.0/10
        if (b0 == 100 && (b1 & 0xC0) == 0x40) return false;
        // 127.0.0.0/8
        if (b0 == 127) return false;
        // 169.254.0.0/16
        if (b0 == 169 && b1 == 254) return false;
        // 172.16.0.0/12
        if (b0 == 172 && (b1 >= 16 && b1 <= 31)) return false;
        // 192.168.0.0/16
        if (b0 == 192 && b1 == 168) return false;
        // 224.0.0.0/4 组播
        if (b0 >= 224 && b0 <= 239) return false;
        // 240.0.0.0/4 保留
        if (b0 >= 240) return false;
        // 192.0.0.0/24 保留地址块（含192.0.2.0/24等文档用途）
        if (b0 == 192 && b1 == 0) return false;

        return true;
    }
